qry:select.qry:xquery:
	for $r in sql('
	SELECT 					
		CYD17_TERCEROS.oi_tercero,
		CYD01_CURSOS.c_curso,
		CYD01_CURSOS.d_curso,
		CYD17_TERCEROS.c_tercero,
		CYD17_TERCEROS.d_ape_y_nom,
		CYD17_TERCEROS.d_empresa,
		CYD02_DICTADOS.f_inicio,
		CYD02_DICTADOS.f_fin
	FROM 
		CYD17_TERCEROS,
		CYD02_INSCRIPTOS,
		CYD01_CURSOS,
		CYD02_DICTADOS
	JOIN
		CYD17_TERCEROS.oi_tercero INNER CYD02_INSCRIPTOS.oi_tercero,
		CYD02_DICTADOS.oi_dictado INNER CYD02_INSCRIPTOS.oi_dictado,
		CYD02_DICTADOS.oi_curso INNER CYD01_CURSOS.oi_curso
	WHERE 1 = 1
	{%? (#FILTRO:@f_desde!='') 
		{% AND CYD02_DICTADOS.f_inicio >= {Datetime(#FILTRO:@f_desde)} %} 
		{%  %} 
	%}
	{%? (#FILTRO:@f_hasta!='') 
		{% AND CYD02_DICTADOS.f_fin < {Datetime(Number(Datetime(#FILTRO:@f_hasta))+1)} %} 
		{%  %} 
	%}					
	{%? (#FILTRO:@oi_curso!='') 
		{% AND CYD01_CURSOS.oi_curso = {#FILTRO:@oi_curso} %} 
		{%  %} 
	%}
	{%? (string(#FILTRO:DICTADOS/DICTADO/@id)!='') 
		{% AND CYD02_DICTADOS.oi_dictado in ({%=string(#FILTRO:DICTADOS/DICTADO/@id)%}) %} 
		{%  %} 
	%}					
	ORDER BY 
		c_tercero ASC, f_inicio ASC
')/ROWS/ROW
